1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type Step = { op: "quote"; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
14	
15	const quotePremium = (items: Item[]): number => {
16	  const basePremium = items.reduce((total, item) => total + basePremiumFor(item), 0);
17	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
18	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
19	};
20	
21	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
22	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
23	});
24

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---------- Simple quote: empty + single items ----------
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("single plain sword (newcomer, first contract) → premium = 100 base + 10 first insurance + 5 fee = 115 G", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
17	    });
18	    expect(result).toEqual({ results: [{ premium: 115 }] });
19	  });
20	  it("single plain amulet (newcomer, first contract) → premium = 60 + 6 + 5 = 71 G", () => {
21	    const result = runScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 71 }] });
26	  });
27	  it.todo("single plain staff (newcomer, first contract) → premium = 80 + 8 + 5 = 93 G");
28	  it.todo("single plain potion (newcomer, first contract) → premium = 40 + 4 + 5 = 49 G");
29	
30	  // ---------- Components and block-of-3 ----------
31	  it.todo("2 runes → 50 G base premium (no block)");
32	  it.todo("3 runes → 60 G base premium (block applies)");
33	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
34	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3 alike)");
35	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
36	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
37	
38	  // ---------- Item-level modifiers ----------
39	  it.todo("cursed sword (newcomer, first contract) → 100 + 50 curse + 15 first insurance + 5 fee = 170 G");
40	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
41	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
42	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
43	
44	  // ---------- Policy-wide modifiers ----------
45	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
46	  it.todo("customer with less than 2 years → no loyalty discount");
47	  it.todo("second quote in scenario → follow-up contract discount applies");
48	
49	  // ---------- Modifier scope on multi-item policies ----------
50	  it.todo("cursed sword + plain amulet → 100 + 60 + 50 curse = 210 G + 10 first ins on sword + 6 first ins on amulet + 5 fee");
51	  it.todo("first insurance surcharge applies per item, not per policy");
52	
53	  // ---------- Rounding in MHPCO's favor ----------
54	  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");
55	  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");
56	
57	  // ---------- Integration premium examples ----------
58	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
59	  it.todo("long-standing (3y) customer's second contract: cursed sword enchantment 7 → premium 160 G");
60	
61	  // ---------- Claims: simple cases ----------
62	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 G (full minus deductible)");
63	  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100 G (full minus deductible)");
64	
65	  // ---------- Claims: special clauses ----------
66	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (dragon: full, minus deductible)");
67	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");
68	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
69	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (high-enchantment then deductible)");
70	
71	  // ---------- Claims: deductible per damage event ----------
72	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies per item)");
73	
74	  // ---------- Claims: cap ----------
75	  it.todo("cursed sword (insurance value 1000) → cap 2000 G (based on unmodified insurance value)");
76	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
77	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block does not affect insurance sum)");
78	  it.todo("sword cap 2000 G, two successive claims of 1500: first payout 1400, cap remaining 600; second payout 600, cap remaining 0");
79	
80	  // ---------- Claims: multiple items of same type ----------
81	  it.todo("policy of two swords → insurance sum 2000 G, cap 4000 G");
82	  it.todo("two swords insured, two sword damage entries → each treated as separate damage with own deductible");
83	  it.todo("damages has more entries of a type than insured → CLI exits non-zero");
84	
85	  // ---------- Edge cases / errors ----------
86	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results on stdout");
87	  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero");
88	  it.todo("claim with damage entry of unknown item type → CLI exits non-zero");
89	  it.todo("claim with negative damage amount → CLI exits non-zero");
90	
91	  // ---------- CLI / multi-step scenario ----------
92	  it.todo("scenario with quote then claim returns results array of matching length and order");
93	  it.todo("claim's policy field references quote step by zero-based index");
94	});
